@page "/board"
@using sv_88c070a41de447aca6ce693cd9a1a2df.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <!-- Stats Bar -->
    <div class="stats-bar">
        <span class="stat-item"><strong>Total:</strong> @filteredTasks.Count</span>
        <span class="stat-item"><strong>To Do:</strong> @GetColumnTasks("To Do").Count</span>
        <span class="stat-item"><strong>In Progress:</strong> @GetColumnTasks("In Progress").Count</span>
        <span class="stat-item"><strong>Done:</strong> @GetColumnTasks("Done").Count</span>
        <span class="stat-item stat-overdue"><strong>Overdue:</strong> @filteredTasks.Count(t => t.DueDate < DateTime.Today)</span>
    </div>

    <!-- Search Bar -->
    <div class="search-bar">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchQuery" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="kanban-board">
        @foreach (var column in columns)
        {
            var columnTasks = GetColumnTasks(column);
            <div class="kanban-column">
                <div class="column-header">
                    <h3>@column <span class="badge">@columnTasks.Count</span></h3>
                </div>
                <div class="column-body">
                    @foreach (var task in columnTasks)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="priority-badge priority-@task.Priority.ToLower()">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                            <div class="task-actions">
                                @if (GetColumnIndex(column) > 0)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTask(task, -1)">Move Left</button>
                                }
                                @if (GetColumnIndex(column) < columns.Length - 1)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTask(task, 1)">Move Right</button>
                                }
                            </div>
                        </div>
                    }
                </div>
                @if (addingToColumn == column)
                {
                    <div class="add-task-form">
                        <input type="text" class="form-control" placeholder="Title" @bind="newTitle" />
                        <input type="text" class="form-control" placeholder="Assignee" @bind="newAssignee" />
                        <select class="form-control" @bind="newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" class="form-control" @bind="newDueDate" />
                        <div class="form-buttons">
                            <button class="btn btn-sm btn-primary" @onclick="() => SaveTask(column)">Save</button>
                            <button class="btn btn-sm btn-secondary" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary add-task-btn"
                            @onclick="() => ShowAddForm(column)">Add Task</button>
                }
            </div>
        }
    </div>
}

<style>
    .stats-bar {
        display: flex;
        gap: 1.5rem;
        padding: 0.75rem 1rem;
        background: #f8f9fa;
        border-radius: 0.5rem;
        margin-bottom: 1rem;
        flex-wrap: wrap;
    }
    .stat-overdue { color: #dc3545; }
    .search-bar { margin-bottom: 1rem; max-width: 400px; }
    .kanban-board {
        display: flex;
        gap: 1rem;
        align-items: flex-start;
    }
    .kanban-column {
        flex: 1;
        background: #f1f3f5;
        border-radius: 0.5rem;
        padding: 0.75rem;
        min-width: 250px;
    }
    .column-header h3 {
        font-size: 1.1rem;
        margin: 0 0 0.5rem;
    }
    .column-header .badge {
        background: #6c757d;
        color: #fff;
        border-radius: 10px;
        padding: 0.2rem 0.5rem;
        font-size: 0.8rem;
    }
    .task-card {
        background: #fff;
        border: 1px solid #dee2e6;
        border-radius: 0.4rem;
        padding: 0.75rem;
        margin-bottom: 0.5rem;
    }
    .task-title { font-weight: 600; margin-bottom: 0.25rem; }
    .task-assignee { font-size: 0.85rem; color: #6c757d; margin-bottom: 0.25rem; }
    .task-due { font-size: 0.8rem; color: #495057; margin-top: 0.25rem; }
    .priority-badge {
        display: inline-block;
        padding: 0.15rem 0.5rem;
        border-radius: 0.25rem;
        font-size: 0.75rem;
        font-weight: 600;
        color: #fff;
    }
    .priority-high { background-color: #dc3545; }
    .priority-medium { background-color: #ffc107; color: #212529; }
    .priority-low { background-color: #28a745; }
    .task-actions { margin-top: 0.5rem; display: flex; gap: 0.25rem; }
    .add-task-form {
        display: flex;
        flex-direction: column;
        gap: 0.4rem;
        margin-top: 0.5rem;
    }
    .form-buttons { display: flex; gap: 0.5rem; }
    .add-task-btn { margin-top: 0.5rem; width: 100%; }
</style>

@code {
    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private string? errorMessage;
    private string searchQuery = string.Empty;

    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today.AddDays(7);

    private static readonly string[] columns = { "To Do", "In Progress", "Done" };

    private List<TaskItem> filteredTasks =>
        string.IsNullOrWhiteSpace(searchQuery)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase)).ToList();

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        filteredTasks.Where(t => t.Status == status).ToList();

    private int GetColumnIndex(string column) => Array.IndexOf(columns, column);

    private async Task MoveTask(TaskItem task, int direction)
    {
        var currentIndex = GetColumnIndex(task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void ShowAddForm(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => addingToColumn = null;

    private async Task SaveTask(string column)
    {
        if (string.IsNullOrWhiteSpace(newTitle)) return;

        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
            allTasks.Add(created with { Status = column });
            addingToColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

